```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CSV to Table</title>
<style>
  table {
    border-collapse: collapse;
    width: 100%;
  }
  th, td {
    border: 1px solid #ddd;
    padding: 8px;
    text-align: left;
  }
  th {
    background-color: #f0f0f0;
  }
  tr:nth-child(even) {
    background-color: #f9f9f9;
  }
</style>
</head>
<body>

<textarea id="csvData" rows="10" cols="50"></textarea>
<button onclick="parseCSV()">Parse CSV</button>
<div id="tableContainer"></div>

<script>
  function parseCSV() {
    const csvData = document.getElementById('csvData').value;
    const rows = csvData.trim().split('\n');
    const tableData = [];
    for (let row of rows) {
      tableData.push(parseRow(row));
    }
    createTable(tableData);
  }

  function parseRow(row) {
    const quoted = row.includes('"');
    if (!quoted) {
      return row.split(',').map(field => field.trim());
    } else {
      const regex = /("([^"]|"")*"|[^,]*)/g;
      let match;
      const fields = [];
      while ((match = regex.exec(row)) !== null) {
        let field = match[0];
        if (field.startsWith('"') && field.endsWith('"')) {
          field = field.slice(1, -1).replace(/""/g, '"');
        } else {
          field = field.trim();
        }
        fields.push(field);
      }
      return fields;
    }
  }

  function createTable(tableData) {
    const maxColumns = Math.max(...tableData.map(row => row.length));
    const tableRows = [];
    for (let row of tableData) {
      tableRows.push(row.concat(Array(maxColumns - row.length).fill('')));
    }
    const tableHtml = tableRows.map((row, rowIndex) => {
      return `
        <tr>
          ${row.map((field, columnIndex) => `
            <td>${field.replace(/"/g, '')}</td>
          `).join('')}
        </tr>
      `;
    }).join('');
    const table = `
      <table>
        <thead>
          <tr>
            ${Array(maxColumns).fill().map((_, index) => `<th>Column ${index + 1}</th>`).join('')}
          </tr>
        </thead>
        <tbody>
          ${tableHtml}
        </tbody>
      </table>
    `;
    document.getElementById('tableContainer').innerHTML = table;
  }
</script>

</body>
</html>
```

